#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <string.h>
#include <ctype.h>

#define MAX 1000

int main() {
    int N;
    char use_numbers[5], use_special_chars[5];
    char password[MAX+3];
    char alphabet[] = "abcdefghijklmnopqrstuvwxyz";
    char special_chars[] = "!@#$%^&*()_+";
    char numbers[] = "0123456789";
    int i, j, k, l;

    scanf("%d", &N);
    getchar();
    fgets(use_numbers, 5, stdin);
    use_numbers[strcspn(use_numbers, "\n")] = 0;
    fgets(use_special_chars, 5, stdin);
    use_special_chars[strcspn(use_special_chars, "\n")] = 0;

    srand(time(NULL));

    for (i = 0; i < N-2; i++) {
        int random_index = rand() % strlen(alphabet);
        password[i] = alphabet[random_index];
    }

    if (strcmp(use_numbers, "Yes") == 0) {
        int random_index = rand() % strlen(numbers);
        password[N-2] = numbers[random_index];
    } else {
        int random_index = rand() % strlen(alphabet);
        password[N-2] = alphabet[random_index];
    }

    if (strcmp(use_special_chars, "Yes") == 0) {
        int random_index = rand() % strlen(special_chars);
        password[N-1] = special_chars[random_index];
    } else {
        int random_index = rand() % strlen(alphabet);
        password[N-1] = alphabet[random_index];
    }

    password[N] = '\0';

    printf("%s\n", password);

    return 0;
}

