import java.util.Random;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        scanner.nextLine();
        String use_numbers = scanner.nextLine();
        String use_special_chars = scanner.nextLine();
        char[] password = new char[N];
        String alphabet = "abcdefghijklmnopqrstuvwxyz";
        String special_chars = "!@#$%^&*()_+";
        String numbers = "0123456789";
        Random random = new Random();

        for (int i = 0; i < N-2; i++) {
            int random_index = random.nextInt(alphabet.length());
            password[i] = alphabet.charAt(random_index);
        }

        if (use_numbers.equals("Yes")) {
            int random_index = random.nextInt(numbers.length());
            password[N-2] = numbers.charAt(random_index);
        } else {
            int random_index = random.nextInt(alphabet.length());
            password[N-2] = alphabet.charAt(random_index);
        }

        if (use_special_chars.equals("Yes")) {
            int random_index = random.nextInt(special_chars.length());
            password[N-1] = special_chars.charAt(random_index);
        } else {
            int random_index = random.nextInt(alphabet.length());
            password[N-1] = alphabet.charAt(random_index);
        }

        System.out.println(new String(password));
    }
}

